const { Client } = require('@elastic/elasticsearch');

// Initialize Elasticsearch client
const client = new Client({
  node: 'http://localhost:9200',
});

async function advancedSearch(queryParams) {
  const { searchTerms, scriptLogic } = queryParams;

  // Construct the query DSL
  const queryDSL = {
    query: {
      function_score: {
        query: {
          match: {
            _all: searchTerms,
          },
        },
        script_score: {
          script: {
            source: scriptLogic,
          },
        },
      },
    },
  };

  try {
    // Execute the search
    const result = await client.search({
      index: 'your_index_name',
      body: queryDSL,
    });

    return result;
  } catch (error) {
    console.error('Error executing search:', error);
    throw error;
  }
}

